interface ProposalModalProps {
  call: FundingCall | null;
  isOpen: boolean;
  onClose: () => void;
}

const ProposalModal: React.FC<ProposalModalProps> = ({ call, isOpen, onClose }) => {
  const [userIdea, setUserIdea] = useState('');
