    if (!userIdea.trim()) return;
    setIsGenerating(true);
    setError(null);
    try {
      const result = await generateProposal(call, userIdea);
      setProposal(result);
    } catch (err) {
      setError("Failed to generate proposal. Please try again.");
    } finally {
      setIsGenerating(false);
    }
