      "timeline": "A structured text description of the timeline (e.g., Phase 1, Phase 2).",
      "timelinePhases": [
        { "phase": "Name of Phase 1", "startMonth": 1, "durationMonths": 2 },
        { "phase": "Name of Phase 2", "startMonth": 3, "durationMonths": 3 }
      ],
      "executionSteps": [
        { "stepNumber": 1, "title": "Inception", "description": "Short description of this step." },
        { "stepNumber": 2, "title": "Development", "description": "Short description of this step." }
      ],
      "budgetItems": [
        { "category": "Equipment/Travel/Personnel", "item": "Name of item", "cost": "Estimated cost", "justification": "Why this is needed" }
      ],
      "totalBudget": "Sum of costs"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json' 
      }
    });

    const text = response.text || '';
    const jsonString = extractJson(text);
    return JSON.parse(jsonString) as Proposal;

  } catch (error) {
    console.error("Gemini Proposal Generation Error:", error);
    throw new Error("Failed to generate proposal. Please try again.");
  }
};

import React, { useState } from 'react';
import { X, Sparkles, Copy, RefreshCw, FileText, PieChart, Download, Calendar, Workflow, ArrowDown } from 'lucide-react';
import { FundingCall, Proposal } from '../types';
import { generateProposal } from '../services/geminiService';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle } from 'docx';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface ProposalModalProps {
  call: FundingCall | null;
  isOpen: boolean;
  onClose: () => void;
}

const ProposalModal: React.FC<ProposalModalProps> = ({ call, isOpen, onClose }) => {
  const [userIdea, setUserIdea] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [proposal, setProposal] = useState<Proposal | null>(null);
  const [activeTab, setActiveTab] = useState<'proposal' | 'budget' | 'gantt' | 'flow'>('proposal');
  const [error, setError] = useState<string | null>(null);

  if (!isOpen || !call) return null;

  const handleGenerate = async () => {
    if (!userIdea.trim()) return;
    setIsGenerating(true);
    setError(null);
    try {
      const result = await generateProposal(call, userIdea);
      setProposal(result);
    } catch (err) {
      setError("Failed to generate proposal. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const reset = () => {
    setProposal(null);
    setUserIdea('');
    setError(null);
    setActiveTab('proposal');
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const formatProposalText = (p: Proposal) => {
    return `
PROJECT TITLE: ${p.projectTitle}

EXECUTIVE SUMMARY:
${p.executiveSummary}

PROBLEM STATEMENT:
${p.problemStatement}

OBJECTIVES:
${p.objectives.map(o => `- ${o}`).join('\n')}

METHODOLOGY:
${p.methodology}

IMPACT:
${p.impact}

TIMELINE:
${p.timeline}
    `.trim();
  };

  const handleDownloadDocx = async () => {
    if (!proposal || !call) return;

    // Helper to create a section header
    const createHeading = (text: string) => {
      return new Paragraph({
        text: text,
        heading: HeadingLevel.HEADING_1,
        spacing: { before: 400, after: 200 },
      });
    };

    // Helper to create body text
    const createBody = (text: string) => {
      return new Paragraph({
        children: [new TextRun(text)],
        spacing: { after: 200 },
      });
    };

    // Helper to create list items
    const createList = (items: string[]) => {
      return items.map(item => 
        new Paragraph({
          text: item,
          bullet: { level: 0 },
          spacing: { after: 100 },
        })
      );
    };

    // Create Budget Table Rows
    const budgetRows = [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "Category", checking: { type: "auto" }, style: "Strong" })], width: { size: 20, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Item", style: "Strong" })], width: { size: 25, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Justification", style: "Strong" })], width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Cost", style: "Strong" })], width: { size: 15, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
        ],
      }),
      ...proposal.budgetItems.map(item => 
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(item.category)] }),
            new TableCell({ children: [new Paragraph(item.item)] }),
            new TableCell({ children: [new Paragraph(item.justification)] }),
            new TableCell({ children: [new Paragraph(item.cost)] }),
          ],
        })
      ),
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "TOTAL", style: "Strong" })], columnSpan: 3, shading: { fill: "F0F0F0" } }),
          new TableCell({ children: [new Paragraph({ text: proposal.totalBudget, style: "Strong" })], shading: { fill: "F0F0F0" } }),
        ]
      })
    ];

    // Create Timeline Table Rows (Alternative to image for DOCX)
    const timelineRows = [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "Phase", style: "Strong" })], width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Start Month", style: "Strong" })], width: { size: 30, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Duration (Months)", style: "Strong" })], width: { size: 30, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
        ],
      }),
      ...(proposal.timelinePhases || []).map(phase => 
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(phase.phase)] }),
            new TableCell({ children: [new Paragraph(phase.startMonth.toString())] }),
            new TableCell({ children: [new Paragraph(phase.durationMonths.toString())] }),
          ],
        })
      )
    ];

    const doc = new Document({
      sections: [{
        properties: {},
        children: [
          // Title
          new Paragraph({
            text: proposal.projectTitle,
            heading: HeadingLevel.TITLE,
            alignment: "center",
            spacing: { after: 400 },
          }),

          // Metadata
          new Paragraph({
            children: [
              new TextRun({ text: "Funding Call: ", bold: true }),
              new TextRun(call.title),
            ],
            spacing: { after: 100 },
          }),
          new Paragraph({
            children: [
              new TextRun({ text: "Organization: ", bold: true }),
              new TextRun(call.organization),
