            spacing: { after: 400 },
          }),

          // Content
          createHeading("Executive Summary"),
          createBody(proposal.executiveSummary),

          createHeading("Problem Statement"),
          createBody(proposal.problemStatement),

          createHeading("Objectives"),
          ...createList(proposal.objectives),

          createHeading("Methodology"),
          createBody(proposal.methodology),

          createHeading("Impact"),
          createBody(proposal.impact),

          createHeading("Execution Flow"),
          ...(proposal.executionSteps || []).map(step => 
            new Paragraph({
              children: [
                new TextRun({ text: `Step ${step.stepNumber}: ${step.title}`, bold: true }),
                new TextRun({ text: ` - ${step.description}`})
              ],
              spacing: { after: 100 }
            })
          ),

          createHeading("Timeline Execution"),
          createBody(proposal.timeline),
          // Add Timeline Table if available
          ...(proposal.timelinePhases?.length ? [
            new Paragraph({ text: "Project Schedule", heading: HeadingLevel.HEADING_2, spacing: { before: 200, after: 200 } }),
            new Table({
              rows: timelineRows,
              width: { size: 100, type: WidthType.PERCENTAGE },
              borders: {
                top: { style: BorderStyle.SINGLE, size: 1 },
                bottom: { style: BorderStyle.SINGLE, size: 1 },
                left: { style: BorderStyle.SINGLE, size: 1 },
                right: { style: BorderStyle.SINGLE, size: 1 },
                insideHorizontal: { style: BorderStyle.SINGLE, size: 1 },
                insideVertical: { style: BorderStyle.SINGLE, size: 1 },
              }
            })
          ] : []),

          // Budget Section
          new Paragraph({
            text: "Budget Plan",
            heading: HeadingLevel.HEADING_1,
            spacing: { before: 600, after: 200 },
          }),
          new Table({
            rows: budgetRows,
            width: { size: 100, type: WidthType.PERCENTAGE },
            borders: {
              top: { style: BorderStyle.SINGLE, size: 1 },
              bottom: { style: BorderStyle.SINGLE, size: 1 },
              left: { style: BorderStyle.SINGLE, size: 1 },
              right: { style: BorderStyle.SINGLE, size: 1 },
              insideHorizontal: { style: BorderStyle.SINGLE, size: 1 },
              insideVertical: { style: BorderStyle.SINGLE, size: 1 },
            }
          }),
        ],
      }],
    });

    // Native download to avoid external dependency issues
    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `IEEE_Proposal_${call.organization.replace(/\s+/g, '_')}.docx`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // Prepare data for Gantt chart
  const ganttData = proposal?.timelinePhases?.map(phase => ({
    name: phase.phase,
    startOffset: phase.startMonth - 1, // 0-based index for chart
    duration: phase.durationMonths
  })) || [];

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto" aria-labelledby="modal-title" role="dialog" aria-modal="true">
      {/* Backdrop */}
      <div className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity backdrop-blur-sm" onClick={onClose}></div>

      <div className="flex min-h-screen items-center justify-center p-4 text-center sm:p-0">
        <div className="relative transform overflow-hidden rounded-2xl bg-white text-left shadow-2xl transition-all sm:my-8 sm:w-full sm:max-w-4xl flex flex-col max-h-[90vh]">

          {/* Header */}
          <div className="bg-[#00629B] px-4 py-4 sm:px-6 flex justify-between items-center shrink-0">
            <div className="text-white">
              <h3 className="text-lg font-semibold leading-6" id="modal-title">
                {proposal ? 'Draft Proposal Generated' : 'Draft New Proposal'}
