              <p className="text-blue-200 text-sm truncate max-w-md">
                Target: {call.title}
              </p>
            </div>
            <button onClick={onClose} className="rounded-full p-1 hover:bg-white/10 text-white transition-colors">
              <X className="h-6 w-6" />
