import { GoogleGenAI } from "@google/genai";
import { FundingCall, Proposal } from "../types";
import { v4 as uuidv4 } from 'uuid';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to clean JSON string from markdown code blocks and conversational text
const extractJson = (text: string): string => {
  // 1. Try to match markdown code blocks
  const markdownMatch = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (markdownMatch) {
    return markdownMatch[1];
  }

  // 2. Fallback: Find the outermost JSON array or object
  const firstOpenBrace = text.indexOf('{');
  const firstOpenBracket = text.indexOf('[');

  let start = -1;
  let end = -1;

  // Determine if it looks like an object or an array starts first
  if (firstOpenBrace !== -1 && (firstOpenBracket === -1 || firstOpenBrace < firstOpenBracket)) {
    start = firstOpenBrace;
    end = text.lastIndexOf('}');
  } else if (firstOpenBracket !== -1) {
    start = firstOpenBracket;
    end = text.lastIndexOf(']');
  }

  if (start !== -1 && end !== -1 && end > start) {
    return text.substring(start, end + 1);
  }

  // 3. Return original text if no JSON structure found (will likely fail parsing, but good for debugging)
  return text;
};

export const searchFundingCalls = async (query: string): Promise<FundingCall[]> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const prompt = `
    You are an expert research assistant for IEEE members. 
    Your task is to find active and upcoming funding calls, grants, scholarships, and travel awards provided by IEEE Societies, Councils, and Affinity Groups (like IEEE WIE, IEEE YP, IEEE SPS, IEEE CIS, etc.).

    User Query: "${query}"

    Please use Google Search to find real, up-to-date information. 

    Format the output strictly as a JSON array of objects. Do not include any conversational text outside the JSON block.
    Each object must have the following fields:
    - title: (string) The name of the grant or call.
    - organization: (string) The IEEE entity offering it (e.g., "IEEE Computer Society").
    - deadline: (string) The specific deadline date or "Open" if rolling. Format as "YYYY-MM-DD" if possible, or readable text.
    - amount: (string) The monetary value (e.g., "$1,000", "Up to $5,000", "Varies").
    - description: (string) A brief summary of the opportunity (max 30 words).
    - eligibility: (string) Who can apply (e.g., "Student Members", "Graduate Students", "Women in Engineering").
    - url: (string) A direct link to the call page if found, or the society's main funding page.
    - category: (string) One of: "Research", "Travel", "Event", "Scholarship", "Other".

    If you cannot find specific active calls matching the query, find general standing funding programs for the relevant societies.
    Return at least 5-10 results if possible.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const text = response.text || '';
    const jsonString = extractJson(text);

    try {
      const data = JSON.parse(jsonString);

      // Validate and sanitize data
      if (Array.isArray(data)) {
        return data.map((item: any) => ({
          id: uuidv4(),
          title: item.title || "Untitled Opportunity",
          organization: item.organization || "IEEE",
          deadline: item.deadline || "Unknown",
          amount: item.amount || "See details",
          description: item.description || "No description available.",
          eligibility: item.eligibility || "See details",
          url: item.url || "#",
          category: ["Research", "Travel", "Event", "Scholarship", "Other"].includes(item.category) ? item.category : "Other"
        }));
      }
      return [];
    } catch (parseError) {
      console.error("Failed to parse Gemini JSON response:", parseError);
      console.log("Raw text:", text);
      console.log("Extracted JSON:", jsonString);
      throw new Error("Could not structure the search results. Please try again.");
    }

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const generateProposal = async (call: FundingCall, userIdea: string): Promise<Proposal> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    You are an expert grant writer specializing in IEEE funding applications.

    CONTEXT - FUNDING CALL:
    Title: ${call.title}
    Organization: ${call.organization}
    Description: ${call.description}
    Amount Available: ${call.amount}
    Eligibility: ${call.eligibility}

    USER'S PROJECT IDEA:
    "${userIdea}"

    TASK:
    Draft a professional, winning project proposal.
    You must also provide:
    1. A detailed Expense Budget (budgetItems).
    2. An Income/Funding Source plan (incomeItems). Include the requested grant amount here as "Pending". If the project cost exceeds the grant, list other potential sources (e.g., "Department Match", "Self-funding") as "Projected".
    3. A Manpower/Resource Allocation plan (resourceAllocations).

    OUTPUT FORMAT:
    Return strictly a JSON object (no markdown, no extra text) with the following structure:
    {
      "projectTitle": "A professional and catchy title based on the idea",
      "executiveSummary": "A compelling 100-150 word summary.",
      "problemStatement": "Clear definition of the problem being solved.",
      "objectives": ["Objective 1", "Objective 2", "Objective 3"],
      "methodology": "How the project will be executed.",
      "impact": "Expected benefits to the technical community and humanity.",
      "timeline": "A structured text description of the timeline (e.g., Phase 1, Phase 2).",
      "timelinePhases": [
        { "phase": "Name of Phase 1", "startMonth": 1, "durationMonths": 2 },
        { "phase": "Name of Phase 2", "startMonth": 3, "durationMonths": 3 }
      ],
      "executionSteps": [
        { "stepNumber": 1, "title": "Inception", "description": "Short description." },
        { "stepNumber": 2, "title": "Development", "description": "Short description." }
      ],
      "budgetItems": [
        { "category": "Equipment/Travel/Personnel", "item": "Name of item", "cost": "Estimated cost", "justification": "Why this is needed" }
      ],
      "incomeItems": [
        { "source": "IEEE Grant Request", "amount": "${call.amount}", "status": "Pending" },
        { "source": "University Lab Support", "amount": "$500", "status": "Confirmed" }
      ],
      "resourceAllocations": [
        { "role": "Principal Investigator", "count": 1, "duration": "12 months", "responsibility": "Project oversight and reporting" },
        { "role": "Undergraduate Student", "count": 2, "duration": "6 months", "responsibility": "Data collection" }
      ],
      "totalBudget": "Sum of expenses"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json' 
      }
    });

    const text = response.text || '';
    const jsonString = extractJson(text);
    return JSON.parse(jsonString) as Proposal;

  } catch (error) {
    console.error("Gemini Proposal Generation Error:", error);
    throw new Error("Failed to generate proposal. Please try again.");
  }
};

