              )}
            </div>

            {/* Footer Actions */}
            {proposal && (
              <div className="bg-gray-50 px-4 py-3 sm:px-6 sm:flex sm:flex-row-reverse border-t border-gray-200 shrink-0 gap-3">
                <button
