import React, { useState, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import Hero from './components/Hero';
import FundingCard from './components/FundingCard';
import StatsDashboard from './components/StatsDashboard';
import Footer from './components/Footer';
import { ProposalModal } from './components/ProposalModal';
import { FundingCall, SearchState } from './types';
import { searchFundingCalls } from './services/geminiService';
import { Filter, AlertCircle, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<SearchState>({
    query: '',
    isLoading: false,
    results: [],
    error: null,
    searchPerformed: false
  });

  const [filterCategory, setFilterCategory] = useState<string>('All');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedCall, setSelectedCall] = useState<FundingCall | null>(null);

  const handleSearch = useCallback(async (query: string) => {
    setState(prev => ({ ...prev, isLoading: true, error: null, query, searchPerformed: true }));

    try {
      const results = await searchFundingCalls(query);
      setState(prev => ({ ...prev, isLoading: false, results }));
    } catch (error: any) {
      console.error(error);
      setState(prev => ({ 
        ...prev, 
        isLoading: false, 
        error: "Failed to fetch funding calls. Please verify your API Key and try again." 
      }));
    }
  }, []);

  const handleDraftProposal = (call: FundingCall) => {
    setSelectedCall(call);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedCall(null);
  };

  const filteredResults = state.results.filter(call => {
    if (filterCategory === 'All') return true;
    return call.category === filterCategory;
  });

  const categories = ['All', 'Research', 'Travel', 'Scholarship', 'Event', 'Other'];

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <Hero onSearch={handleSearch} isLoading={state.isLoading} />

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-12">

        {/* Loading State */}
        {state.isLoading && (
          <div className="flex flex-col items-center justify-center py-20 text-gray-500 animate-pulse">
            <Loader2 className="w-12 h-12 mb-4 animate-spin text-[#00629B]" />
            <p className="text-lg">Scouring IEEE websites for funding opportunities...</p>
            <p className="text-sm opacity-70">This typically takes 5-10 seconds.</p>
          </div>
        )}

        {/* Error State */}
        {state.error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-6 mb-8 flex items-start text-red-700">
            <AlertCircle className="w-6 h-6 mr-3 mt-0.5 flex-shrink-0" />
            <div>
              <h3 className="font-bold">Error</h3>
              <p>{state.error}</p>
            </div>
          </div>
        )}

        {/* Results Area */}
        {!state.isLoading && state.searchPerformed && !state.error && (
          <div className="space-y-8">

            {/* Stats */}
            <StatsDashboard data={state.results} />

            {/* Filter Bar */}
            {state.results.length > 0 && (
              <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-4 rounded-lg border border-gray-200 shadow-sm sticky top-4 z-20">
                <div className="flex items-center mb-4 sm:mb-0">
                  <span className="font-semibold text-gray-700 mr-2">{state.results.length}</span>
                  <span className="text-gray-500">Opportunities found</span>
                </div>

                <div className="flex items-center overflow-x-auto max-w-full pb-2 sm:pb-0 hide-scrollbar">
                  <Filter className="w-4 h-4 text-gray-400 mr-3 flex-shrink-0" />
                  <div className="flex space-x-2">
                    {categories.map(cat => (
                      <button
                        key={cat}
                        onClick={() => setFilterCategory(cat)}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-colors whitespace-nowrap ${
                          filterCategory === cat
                            ? 'bg-[#00629B] text-white'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* Grid */}
            {filteredResults.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredResults.map(call => (
                  <FundingCard 
                    key={call.id} 
                    call={call} 
                    onDraftProposal={handleDraftProposal}
                  />
                ))}
              </div>
            ) : (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                <p className="text-gray-500 text-lg">No results found for this category.</p>
                <button 
                  onClick={() => setFilterCategory('All')}
                  className="mt-4 text-[#00629B] font-medium hover:underline"
                >
                  Clear filters
                </button>
              </div>
            )}
          </div>
        )}

        {/* Empty State / Welcome */}
        {!state.searchPerformed && (
          <div className="text-center py-20">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-blue-50 text-[#00629B] mb-6">
              <Sparkles className="w-8 h-8" />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">Ready to explore?</h2>
            <p className="text-gray-500 max-w-md mx-auto">
              Enter a search term above (e.g., "Student Travel Grants") to find current funding calls from across the IEEE ecosystem.
            </p>
          </div>
        )}

      </main>

      <Footer />

      {/* Proposal Modal */}
      <ProposalModal 
        isOpen={isModalOpen} 
        call={selectedCall} 
        onClose={handleCloseModal} 
      />
    </div>
  );
};

// Simple Icon for empty state
function Sparkles(props: React.SVGProps<SVGSVGElement>) {
  return (
    <svg 
      xmlns="http://www.w3.org/2000/svg" 
      width="24" 
      height="24" 
      viewBox="0 0 24 24" 
      fill="none" 
      stroke="currentColor" 
      strokeWidth="2" 
      strokeLinecap="round" 
      strokeLinejoin="round" 
      {...props}
    >
      <path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z" />
    </svg>
  )
}

export default App;

export interface FundingCall {
  id: string;
  title: string;
  organization: string; // e.g., "IEEE Signal Processing Society"
  deadline: string;
  amount: string;
  description: string;
  eligibility: string;
  url: string;
  category: 'Research' | 'Travel' | 'Event' | 'Scholarship' | 'Other';
}

export interface SearchState {
  query: string;
  isLoading: boolean;
  results: FundingCall[];
  error: string | null;
  searchPerformed: boolean;
}

export enum SortOption {
  DEADLINE_SOONEST = 'DEADLINE_SOONEST',
  AMOUNT_HIGHEST = 'AMOUNT_HIGHEST',
  NEWEST = 'NEWEST'
}

export interface BudgetItem {
  category: string;
  item: string;
  cost: string;
  justification: string;
}

export interface TimelinePhase {
  phase: string;
  startMonth: number; // 1-based index relative to project start
  durationMonths: number;
}

export interface ExecutionStep {
  stepNumber: number;
  title: string;
  description: string;
}

export interface IncomeItem {
  source: string;
  status: string;
  amount: string;
}

export interface ResourceAllocation {
  role: string;
  count: number;
  duration: string;
  responsibility: string;
}

export interface Proposal {
  projectTitle: string;
  executiveSummary: string;
  problemStatement: string;
  objectives: string[];
  methodology: string;
  impact: string;
  timeline: string; // Text description
  timelinePhases: TimelinePhase[]; // Structured data for Gantt chart
  executionSteps: ExecutionStep[]; // Structured data for Flow chart
  budgetItems: BudgetItem[];
  totalBudget: string;
  incomeItems?: IncomeItem[];
  resourceAllocations?: ResourceAllocation[];
}

import React, { useState } from 'react';
import { X, Sparkles, Copy, RefreshCw, FileText, PieChart, Download, Calendar, Workflow, ArrowDown, Users, DollarSign, Wallet, Edit3 } from 'lucide-react';
import { FundingCall, Proposal } from '../types';
import { generateProposal } from '../services/geminiService';
import { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle } from 'docx';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface ProposalModalProps {
  call: FundingCall | null;
  isOpen: boolean;
  onClose: () => void;
}

export const ProposalModal: React.FC<ProposalModalProps> = ({ call, isOpen, onClose }) => {
  const [userIdea, setUserIdea] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [proposal, setProposal] = useState<Proposal | null>(null);
  const [activeTab, setActiveTab] = useState<'proposal' | 'budget' | 'gantt' | 'flow'>('proposal');
  const [error, setError] = useState<string | null>(null);
  const [lastCallId, setLastCallId] = useState<string | null>(null);

  // Reset state when switching to a different funding call
  if (call && call.id !== lastCallId) {
    setLastCallId(call.id);
    setUserIdea('');
    setProposal(null);
    setIsGenerating(false);
    setError(null);
    setActiveTab('proposal');
  }

  if (!isOpen || !call) return null;

  const handleGenerate = async () => {
    if (!userIdea.trim()) return;
    setIsGenerating(true);
    setError(null);
    try {
      const result = await generateProposal(call, userIdea);
      setProposal(result);
    } catch (err) {
      setError("Failed to generate proposal. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const reset = () => {
    setProposal(null);
    setUserIdea('');
    setError(null);
    setActiveTab('proposal');
  };

  const handleRedraft = () => {
    setProposal(null);
    setError(null);
    setActiveTab('proposal');
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const formatProposalText = (p: Proposal) => {
    return `
PROJECT TITLE: ${p.projectTitle}

EXECUTIVE SUMMARY:
${p.executiveSummary}

PROBLEM STATEMENT:
${p.problemStatement}

OBJECTIVES:
${p.objectives.map(o => `- ${o}`).join('\n')}

METHODOLOGY:
${p.methodology}

IMPACT:
${p.impact}

TIMELINE:
${p.timeline}
    `.trim();
  };

  const handleDownloadDocx = async () => {
    if (!proposal || !call) return;

    // Helper to create a section header
    const createHeading = (text: string) => {
      return new Paragraph({
        text: text,
        heading: HeadingLevel.HEADING_1,
        spacing: { before: 400, after: 200 },
      });
    };

    // Helper to create body text
    const createBody = (text: string) => {
      return new Paragraph({
        children: [new TextRun(text)],
        spacing: { after: 200 },
      });
    };

    // Helper to create list items
    const createList = (items: string[]) => {
      return items.map(item => 
        new Paragraph({
          text: item,
          bullet: { level: 0 },
          spacing: { after: 100 },
        })
      );
    };

    // Create Expenses Table
    const budgetRows = [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "Category", checking: { type: "auto" }, style: "Strong" })], width: { size: 20, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Item", style: "Strong" })], width: { size: 25, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Justification", style: "Strong" })], width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Cost", style: "Strong" })], width: { size: 15, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
        ],
      }),
      ...proposal.budgetItems.map(item => 
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(item.category)] }),
            new TableCell({ children: [new Paragraph(item.item)] }),
            new TableCell({ children: [new Paragraph(item.justification)] }),
            new TableCell({ children: [new Paragraph(item.cost)] }),
          ],
        })
      ),
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "TOTAL EXPENSES", style: "Strong" })], columnSpan: 3, shading: { fill: "F0F0F0" } }),
          new TableCell({ children: [new Paragraph({ text: proposal.totalBudget, style: "Strong" })], shading: { fill: "F0F0F0" } }),
        ]
      })
    ];

    // Create Income Table
    const incomeRows = [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "Funding Source", style: "Strong" })], width: { size: 50, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Status", style: "Strong" })], width: { size: 25, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Amount", style: "Strong" })], width: { size: 25, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
        ],
      }),
      ...(proposal.incomeItems || []).map(item => 
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(item.source)] }),
            new TableCell({ children: [new Paragraph(item.status)] }),
            new TableCell({ children: [new Paragraph(item.amount)] }),
          ],
        })
      )
    ];

    // Create Resources Table
    const resourceRows = [
      new TableRow({
        children: [
          new TableCell({ children: [new Paragraph({ text: "Role", style: "Strong" })], width: { size: 30, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Count", style: "Strong" })], width: { size: 10, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Duration", style: "Strong" })], width: { size: 20, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
          new TableCell({ children: [new Paragraph({ text: "Key Responsibility", style: "Strong" })], width: { size: 40, type: WidthType.PERCENTAGE }, shading: { fill: "E0E0E0" } }),
        ],
      }),
      ...(proposal.resourceAllocations || []).map(res => 
        new TableRow({
          children: [
            new TableCell({ children: [new Paragraph(res.role)] }),
            new TableCell({ children: [new Paragraph(res.count.toString())] }),
            new TableCell({ children: [new Paragraph(res.duration)] }),
            new TableCell({ children: [new Paragraph(res.responsibility)] }),
          ],
        })
      )
    ];

    const doc = new Document({
      sections: [{
        properties: {},
        children: [
          // Title
          new Paragraph({
            text: proposal.projectTitle,
            heading: HeadingLevel.TITLE,
            alignment: "center",
            spacing: { after: 400 },
          }),

          // Content Sections
          createHeading("Executive Summary"),
          createBody(proposal.executiveSummary),

          createHeading("Problem Statement"),
          createBody(proposal.problemStatement),

          createHeading("Objectives"),
          ...createList(proposal.objectives),

          createHeading("Methodology"),
          createBody(proposal.methodology),

          createHeading("Impact"),
          createBody(proposal.impact),

          createHeading("Execution Plan"),
          ...(proposal.executionSteps || []).map(step => 
            new Paragraph({
              children: [
                new TextRun({ text: `Step ${step.stepNumber}: ${step.title}`, bold: true }),
                new TextRun({ text: ` - ${step.description}`})
              ],
              spacing: { after: 100 }
            })
          ),

          // Financials
          new Paragraph({ text: "Financial Plan", heading: HeadingLevel.HEADING_1, spacing: { before: 600, after: 200 } }),

          new Paragraph({ text: "Projected Expenses", heading: HeadingLevel.HEADING_2, spacing: { after: 200 } }),
          new Table({
            rows: budgetRows,
            width: { size: 100, type: WidthType.PERCENTAGE },
            borders: {
              top: { style: BorderStyle.SINGLE, size: 1 },
              bottom: { style: BorderStyle.SINGLE, size: 1 },
              left: { style: BorderStyle.SINGLE, size: 1 },
              right: { style: BorderStyle.SINGLE, size: 1 },
              insideHorizontal: { style: BorderStyle.SINGLE, size: 1 },
              insideVertical: { style: BorderStyle.SINGLE, size: 1 },
            }
          }),

          new Paragraph({ text: "Income & Funding Sources", heading: HeadingLevel.HEADING_2, spacing: { before: 400, after: 200 } }),
          new Table({
            rows: incomeRows,
            width: { size: 100, type: WidthType.PERCENTAGE },
            borders: {
              top: { style: BorderStyle.SINGLE, size: 1 },
              bottom: { style: BorderStyle.SINGLE, size: 1 },
              left: { style: BorderStyle.SINGLE, size: 1 },
              right: { style: BorderStyle.SINGLE, size: 1 },
              insideHorizontal: { style: BorderStyle.SINGLE, size: 1 },
              insideVertical: { style: BorderStyle.SINGLE, size: 1 },
            }
          }),

          // Resources (Included in DOCX but removed from Tab View)
