    setLastCallId(call.id);
    setUserIdea('');
    setTeamMembers([{ name: '', affiliation: '', role: 'Principal Investigator' }]);
    setProposal(null);
    setIsGenerating(false);
    setError(null);
    setActiveTab('proposal');
